import { describe, expect, it } from '@a0n/gnosis/test';
import {
  compileGgTopologyToGrassmannianCache,
  decideGgGrassmannianCacheSkip,
  diffGgGrassmannianCachePlans,
} from './gg-grassmannian-cache';

const FANOUT_TOPOLOGY = `
  (entry_0: Entry:PolyglotBridgeEntry { module: 'fanout', function: 'main' })
  (statement_1: Statement:PolyglotBridgeCall { bind_pattern: 'user_profile', callee: 'Promise.all', branches: 2 })
  (foil_join_4: Join:PolyglotBridgeJoin:FoilForkFold { arity: 2, bind_pattern: 'user_profile' })
  (foil_branch_5: Branch:PolyglotBridgeCall:FoilBranch { branch_index: 0, callee: 'loadUser' })
  (foil_branch_6: Branch:PolyglotBridgeCall:FoilBranch { branch_index: 1, callee: 'loadProfile' })
  (entry_0)-[:PROCESS]->(statement_1)
  (statement_1)-[:FORK { family: 'FoilForkFold' }]->(foil_branch_5 | foil_branch_6)
  (foil_branch_5 | foil_branch_6)-[:FOLD { family: 'FoilForkFold' }]->(foil_join_4)
`;

describe('GG Grassmannian cache compiler', () => {
  it('lowers fanout topology into certified QBracket lanes', () => {
    const plan = compileGgTopologyToGrassmannianCache(FANOUT_TOPOLOGY, {
      sourceId: 'fanout-smoke',
    });

    expect(plan.laneCount).toBe(196884);
    expect(plan.lanes.length).toBe(8);
    expect(plan.certificate.defectRank).toBe(8);
    expect(plan.certificate.theoremRefs).toContain('Gnosis.BracketedSpace.QBracket');
    expect(plan.lanes.some((lane) => lane.kind === 'fork')).toBe(true);
    expect(plan.lanes.some((lane) => lane.kind === 'fold')).toBe(true);
    expect(
      plan.lanes.every((lane) => lane.qBracket.lower <= lane.qBracket.upper)
    ).toBe(true);
  });

  it('diffs topology edits into sparse Grassmannian XOR lanes', () => {
    const previous = compileGgTopologyToGrassmannianCache(FANOUT_TOPOLOGY);
    const next = compileGgTopologyToGrassmannianCache(
      FANOUT_TOPOLOGY.replace("callee: 'loadProfile'", "callee: 'loadProfileCached'")
    );
    const unchanged = diffGgGrassmannianCachePlans(previous, previous);
    const changed = diffGgGrassmannianCachePlans(previous, next);

    expect(unchanged.defectRank).toBe(0);
    expect(unchanged.certificate.balanced).toBe(true);
    expect(changed.defectRank).toBe(1);
    expect(changed.changedLanes).toHaveLength(1);
    expect(changed.changedLanes[0]?.key).toBe('node:foil_branch_6');
    expect(changed.certificate.balanced).toBe(false);
  });

  it('skips identical current executions before sparse lane diffing', () => {
    const seed = compileGgTopologyToGrassmannianCache(FANOUT_TOPOLOGY);
    const sameCurrent = compileGgTopologyToGrassmannianCache(FANOUT_TOPOLOGY);
    const changedCurrent = compileGgTopologyToGrassmannianCache(
      FANOUT_TOPOLOGY.replace("callee: 'loadUser'", "callee: 'loadUserCached'")
    );

    const skipDecision = decideGgGrassmannianCacheSkip(seed, sameCurrent);
    const replayDecision = decideGgGrassmannianCacheSkip(seed, changedCurrent);

    expect(skipDecision.action).toBe('skip-current-execution');
    expect(skipDecision.canSkip).toBe(true);
    expect(skipDecision.defectRank).toBe(0);
    expect(skipDecision.diff).toBeUndefined();
    expect(replayDecision.action).toBe('replay-changed-lanes');
    expect(replayDecision.canSkip).toBe(false);
    expect(replayDecision.defectRank).toBe(1);
    expect(replayDecision.diff?.changedLanes[0]?.key).toBe('node:foil_branch_5');
  });
});
